// Original tiling water normal map (VFX_ASSETS WS-G).
//
// Generates a seamless 512² normal map from summed, wrap-safe sine ripples and
// writes it to public/assets/textures/water/water_normal.webp. Generated by us
// (ASSETS.md "Original") — no third-party download. The terrain water shader
// samples it as an optional detail layer; with the file absent the shader keeps
// its procedural summed-sine ripple, so the boot floor is unchanged.
//
// Tiling is guaranteed by building every ripple from frequencies that are
// integer numbers of cycles across the texture, so the height field — and thus
// the derived normals — wrap on both axes.
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import sharp from 'sharp';

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..', '..');
const OUT = path.join(ROOT, 'public/assets/textures/water/water_normal.webp');
const N = 512;
const TWO_PI = Math.PI * 2;

// Ripple set: [cyclesX, cyclesY, amplitude, phase]. Whole cycles → seamless tile.
const RIPPLES = [
  [3, 2, 1.0, 0.0],
  [2, 5, 0.7, 1.1],
  [6, 3, 0.5, 2.3],
  [5, 7, 0.35, 0.6],
  [9, 4, 0.22, 3.0],
  [4, 10, 0.18, 1.7]
];

function height(u, v) {
  let h = 0;
  for (const [cx, cy, amp, ph] of RIPPLES) {
    h += Math.sin(TWO_PI * (cx * u + cy * v) + ph) * amp;
  }
  return h;
}

const data = Buffer.alloc(N * N * 3);
const STRENGTH = 1.4;
const eps = 1 / N;
for (let y = 0; y < N; y++) {
  for (let x = 0; x < N; x++) {
    const u = x / N;
    const v = y / N;
    // central differences (wrap via modulo) → tangent-space normal
    const hx = height((u + eps) % 1, v) - height((u - eps + 1) % 1, v);
    const hy = height(u, (v + eps) % 1) - height(u, (v - eps + 1) % 1);
    let nx = -hx * STRENGTH;
    let ny = -hy * STRENGTH;
    let nz = 1;
    const inv = 1 / Math.hypot(nx, ny, nz);
    nx *= inv; ny *= inv; nz *= inv;
    const i = (y * N + x) * 3;
    data[i] = Math.round((nx * 0.5 + 0.5) * 255);
    data[i + 1] = Math.round((ny * 0.5 + 0.5) * 255);
    data[i + 2] = Math.round((nz * 0.5 + 0.5) * 255);
  }
}

fs.mkdirSync(path.dirname(OUT), { recursive: true });
await sharp(data, { raw: { width: N, height: N, channels: 3 } })
  .webp({ quality: 90, effort: 6 })
  .toFile(OUT);

console.log(`wrote ${path.relative(ROOT, OUT)}`);
